import React, { createContext, useState, useContext, useEffect } from 'react';

const DataContext = createContext(null);

export const DataProvider = ({ children }) => {
  // --- HÀM KHỞI TẠO DỮ LIỆU TỪ LOCAL STORAGE HOẶC DÙNG MẶC ĐỊNH ---
  const getInitialData = (key, defaultValue) => {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : defaultValue;
  };

  // 1. Dữ liệu Staff (Mặc định có 1 Admin và 2 Staff nếu chưa có localStorage)
  const [staffList, setStaffList] = useState(() => getInitialData('staffList', [
    { id: 1, username: 'nv1', password: '123', name: 'Nguyễn Văn A', role: 'staff', status: 'active' },
    { id: 2, username: 'nv2', password: '123', name: 'Trần Thị B', role: 'staff', status: 'active' }
  ]));

  // 2. Dữ liệu Tasks
  const [tasks, setTasks] = useState(() => getInitialData('tasks', [
    { 
      id: 1715000000000, 
      title: 'Thiết kế Logo mới', 
      assigneeId: 1, 
      progress: 50, 
      startDate: '2023-10-20',
      deadline: '2023-10-25', 
      discipline: 'Trừ 10% KPI tháng', 
      completedDate: null,
      reason: '' 
    }
  ]));

  const [attendanceLogs, setAttendanceLogs] = useState(() => getInitialData('attendanceLogs', []));
  const [facilityLogs, setFacilityLogs] = useState(() => getInitialData('facilityLogs', []));

  // --- USE EFFECT: TỰ ĐỘNG LƯU VÀO LOCAL STORAGE KHI STATE THAY ĐỔI ---
  useEffect(() => { localStorage.setItem('staffList', JSON.stringify(staffList)); }, [staffList]);
  useEffect(() => { localStorage.setItem('tasks', JSON.stringify(tasks)); }, [tasks]);
  useEffect(() => { localStorage.setItem('attendanceLogs', JSON.stringify(attendanceLogs)); }, [attendanceLogs]);
  useEffect(() => { localStorage.setItem('facilityLogs', JSON.stringify(facilityLogs)); }, [facilityLogs]);

  // --- CÁC HÀM XỬ LÝ (ACTIONS) ---

  const addStaff = (s) => setStaffList([...staffList, { ...s, id: Date.now(), status: 'active' }]);
  
  const deleteStaff = (id) => {
    setStaffList(staffList.filter(staff => staff.id !== id));
  };

  const updatePassword = (id, newPass) => {
    setStaffList(staffList.map(s => s.id === id ? { ...s, password: newPass } : s));
  };

  // Hàm cập nhật trạng thái nhân sự (Bổ nhiệm/Đình chỉ)
  const updateStaffStatus = (id, newStatus) => {
    setStaffList(staffList.map(s => s.id === id ? { ...s, status: newStatus } : s));
  };

  const addTask = (t) => setTasks([...tasks, { 
    ...t, 
    id: Date.now(), 
    progress: 0, 
    reason: '',
    completedDate: null 
  }]);

  // Hàm cập nhật task (bao gồm cả việc đổi người Assign - Cover)
  const updateTask = (taskId, newDat) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, ...newDat } : t));
  };

  const updateTaskProgress = (id, p, reason = '') => {
    const now = new Date().toISOString().split('T')[0];
    setTasks(tasks.map(t => 
      t.id === id ? { 
        ...t, 
        progress: p, 
        reason: reason,
        completedDate: p === 100 ? now : null 
      } : t
    ));
  };

  const addAttendance = (log) => setAttendanceLogs([...attendanceLogs, log]);
  const addFacilityLog = (log) => setFacilityLogs([...facilityLogs, log]);

  return (
    <DataContext.Provider value={{ 
      staffList, addStaff, deleteStaff, updatePassword, updateStaffStatus,
      tasks, addTask, updateTask, updateTaskProgress, 
      attendanceLogs, addAttendance, 
      facilityLogs, addFacilityLog 
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => useContext(DataContext);
